@namespace Lumeo

<svg viewBox="0 0 100 @Height"
     preserveAspectRatio="none"
     class="@CssClass"
     style="@InlineStyle"
     aria-label="@AriaLabel"
     role="img"
     @attributes="AdditionalAttributes">
    @((MarkupString)_shapesHtml)
</svg>

@code {
    public enum SparkType { Line, Area, Bars }

    /// <summary>The data series to plot. A null or empty series renders a faint flat baseline instead
    /// of a chart. A single value renders as a flat line across the full width.</summary>
    [Parameter] public IEnumerable<double>? Values { get; set; }
    /// <summary>Height of the chart in px. The <c>viewBox</c> width is always normalized to 100 units,
    /// so the SVG scales to fill its container's width. Default: 32.</summary>
    [Parameter] public int Height { get; set; } = 32;
    /// <summary>CSS color for the line/bars/area. Defaults to the theme's primary color
    /// (<c>var(--color-primary, currentColor)</c>) when unset.</summary>
    [Parameter] public string? Color { get; set; }
    /// <summary>Chart shape: a connected <see cref="SparkType.Line"/> (default), a filled
    /// <see cref="SparkType.Area"/> under the line, or discrete <see cref="SparkType.Bars"/>.</summary>
    [Parameter] public SparkType Type { get; set; } = SparkType.Line;
    /// <summary>Fills the area under the line, without switching <see cref="Type"/> to
    /// <see cref="SparkType.Area"/> explicitly.</summary>
    [Parameter] public bool ShowArea { get; set; }
    /// <summary>Highlights the last data point with a filled dot.</summary>
    [Parameter] public bool ShowLast { get; set; }
    /// <summary>
    /// Render a marker dot at every data point with a native SVG <c>&lt;title&gt;</c>
    /// (hover tooltip showing the value) — point highlight + tooltips with no JS.
    /// Off by default. (#275)
    /// </summary>
    [Parameter] public bool ShowTooltips { get; set; }
    /// <summary>Line/outline stroke width. Applied with <c>vector-effect="non-scaling-stroke"</c> so it
    /// stays a constant pixel width regardless of the SVG's scaled size. Default: 1.5.</summary>
    [Parameter] public double StrokeWidth { get; set; } = 1.5;
    /// <summary>Accessible name for the chart (<c>aria-label</c> on the <c>svg</c>, <c>role="img"</c>).
    /// Default: "Trend".</summary>
    [Parameter] public string? AriaLabel { get; set; } = "Trend";
    /// <summary>Additional CSS classes merged onto the root <c>svg</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Additional HTML attributes captured and forwarded to the root <c>svg</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string _shapesHtml = string.Empty;

    private string CssClass => Cx.Merge("inline-block w-full align-middle", Class);

    private string InlineStyle
    {
        get
        {
            var style = $"height: {Height}px;";
            if (!string.IsNullOrEmpty(Color)) style += $" color: {Color};";
            return style;
        }
    }

    protected override void OnParametersSet()
    {
        _shapesHtml = BuildShapes();
    }

    private string BuildShapes()
    {
        var list = Values?.ToList();
        if (list is null || list.Count == 0)
        {
            // Baseline rect so the component has a visible footprint.
            return $"<rect x=\"0\" y=\"{F(Height / 2.0 - 0.5)}\" width=\"100\" height=\"1\" fill=\"var(--color-muted-foreground, currentColor)\" opacity=\"0.35\" />";
        }

        var color = string.IsNullOrEmpty(Color) ? "var(--color-primary, currentColor)" : Color;
        var min = list.Min();
        var max = list.Max();
        var range = max - min;
        const double pad = 2.0;
        var usable = Height - (pad * 2);

        double ScaleY(double v)
        {
            if (range == 0) return Height / 2.0;
            var norm = (v - min) / range;
            return Height - pad - (norm * usable);
        }

        var sb = new System.Text.StringBuilder();

        if (Type == SparkType.Bars)
        {
            var n = list.Count;
            var slot = 100.0 / n;
            var barWidth = Math.Max(0.5, slot - 1);
            var zeroY = Height - pad;
            for (int i = 0; i < n; i++)
            {
                var x = i * slot + (slot - barWidth) / 2.0;
                var y = ScaleY(list[i]);
                var h = Math.Max(0.5, zeroY - y);
                sb.Append($"<rect x=\"{F(x)}\" y=\"{F(y)}\" width=\"{F(barWidth)}\" height=\"{F(h)}\" fill=\"{color}\" />");
            }
        }
        else
        {
            var n = list.Count;
            string pointsStr;
            if (n == 1)
            {
                // A single data point can't form a line segment — a one-coordinate
                // polyline (and the matching zero-width area polygon) render nothing.
                // Emit a flat line across the full width so the sparkline stays visible.
                var ly = ScaleY(list[0]);
                pointsStr = $"0,{F(ly)} 100,{F(ly)}";
            }
            else
            {
                var pts = new System.Text.StringBuilder();
                for (int i = 0; i < n; i++)
                {
                    var x = (double)i / (n - 1) * 100.0;
                    var y = ScaleY(list[i]);
                    if (i > 0) pts.Append(' ');
                    pts.Append($"{F(x)},{F(y)}");
                }
                pointsStr = pts.ToString();
            }

            if (Type == SparkType.Area || ShowArea)
            {
                // pointsStr always spans x=0..100 (incl. the single-point flat line),
                // so the area baseline polygon does too.
                const double firstX = 0.0;
                const double lastX = 100.0;
                var polyPoints = $"{F(firstX)},{F(Height)} {pointsStr} {F(lastX)},{F(Height)}";
                sb.Append($"<polygon points=\"{polyPoints}\" fill=\"{color}\" fill-opacity=\"0.2\" stroke=\"none\" />");
                sb.Append($"<polyline points=\"{pointsStr}\" fill=\"none\" stroke=\"{color}\" stroke-width=\"{F(StrokeWidth)}\" stroke-linecap=\"round\" stroke-linejoin=\"round\" vector-effect=\"non-scaling-stroke\" />");
            }
            else
            {
                sb.Append($"<polyline points=\"{pointsStr}\" fill=\"none\" stroke=\"{color}\" stroke-width=\"{F(StrokeWidth)}\" stroke-linecap=\"round\" stroke-linejoin=\"round\" vector-effect=\"non-scaling-stroke\" />");
            }
        }

        if (ShowLast && list.Count > 0)
        {
            double lx, ly;
            if (Type == SparkType.Bars)
            {
                var n = list.Count;
                var slot = 100.0 / n;
                lx = (n - 1) * slot + slot / 2.0;
                ly = ScaleY(list[^1]);
            }
            else
            {
                var n = list.Count;
                lx = n == 1 ? 50.0 : 100.0;
                ly = ScaleY(list[^1]);
            }
            var r = (Type == SparkType.Area || ShowArea) ? 2.75 : 2.25;
            sb.Append($"<circle cx=\"{F(lx)}\" cy=\"{F(ly)}\" r=\"{F(r)}\" fill=\"{color}\" />");
        }

        // Per-point markers + native <title> hover tooltips (#275). Opt-in.
        if (ShowTooltips)
        {
            var n = list.Count;
            var slot = 100.0 / n;
            for (int i = 0; i < n; i++)
            {
                var cx = Type == SparkType.Bars
                    ? i * slot + slot / 2.0
                    : (n == 1 ? 50.0 : (double)i / (n - 1) * 100.0);
                var cy = ScaleY(list[i]);
                sb.Append($"<circle cx=\"{F(cx)}\" cy=\"{F(cy)}\" r=\"1.75\" fill=\"{color}\"><title>{F(list[i])}</title></circle>");
            }
        }

        return sb.ToString();
    }

    private static string F(double v) => v.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture);
}
